import React, { createContext, useContext, useState, useEffect } from 'react';
import { API_ENDPOINTS, getApiUrl } from '../config/api';
import api from '../services/api';
import toast from 'react-hot-toast';

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    checkSession();
  }, []);

  const checkSession = async () => {
    const sessionId = localStorage.getItem('sessionId');
    const sessionExpiry = localStorage.getItem('sessionExpiry');
    const userRole = localStorage.getItem('userRole');
    if (!sessionId || !sessionExpiry || !userRole) {
      setUser(null);
      setIsAuthenticated(false);
      setIsLoading(false);
      return;
    }
    const expiryDate = new Date(sessionExpiry);
    if (new Date() > expiryDate) {
      logout();
      return;
    }
    setUser({ id: '', email: '', name: userRole, mobile: '', role: userRole, profile_pic: '' });
    setIsAuthenticated(true);
    setIsLoading(false);
  };

  const login = async (formData) => {
    try {
      let endpoint = API_ENDPOINTS.LOGIN;
      if (formData.role === 'Admin') endpoint = API_ENDPOINTS.ADMIN_LOGIN;
      if (formData.role === 'Technician') endpoint = API_ENDPOINTS.TECHNICIAN_LOGIN;
      const response = await api.post(getApiUrl(endpoint), formData);
      if (response.status === 'success' && response.sessionid) {
        localStorage.setItem('sessionId', response.sessionid);
        localStorage.setItem('userRole', formData.role);
        if (response.session_expiry) localStorage.setItem('sessionExpiry', response.session_expiry);
        if (response.data) {
          setUser(response.data);
        } else {
          setUser({ id: '', email: formData.email, name: formData.role, mobile: '', role: formData.role, profile_pic: '' });
        }
        setIsAuthenticated(true);
        toast.success('Login successful!');
        return true;
      } else {
        toast.error(response.message || 'Login failed');
        return false;
      }
    } catch (error) {
      toast.error('Login error');
      return false;
    }
  };

  const logout = () => {
    localStorage.removeItem('sessionId');
    localStorage.removeItem('sessionExpiry');
    localStorage.removeItem('userRole');
    setUser(null);
    setIsAuthenticated(false);
  };

  return (
    <AuthContext.Provider value={{ user, isAuthenticated, isLoading, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);
